async (page) => {
  // Close welcome dialog if present
  await page.evaluate(() => {
    const btn = document.getElementById('close-welcome');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  await page.keyboard.press('Escape');
  await page.waitForTimeout(500);

  // Install state extractor
  await page.addScriptTag({ path: '/home/patnir41/projects/kaetram-agent/state_extractor.js' });
  await page.waitForTimeout(1000);

  // Set up screenshot hook
  if (!page.hasScreenshotHook) {
    page.hasScreenshotHook = true;
    page.on('console', async (msg) => {
      if (msg.text() === 'LIVE_SCREENSHOT_TRIGGER') {
        page.screenshot({ path: '/tmp/kaetram_agent_0/state/live_screen.png', type: 'png' }).catch(() => {});
      }
    });
  }

  // Set attack style to Hack (index 0)
  await page.evaluate(() => {
    if (window.game && window.game.player) {
      window.game.player.setAttackStyle(0);
    }
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}
